t.script:
document.addEventListener('DOMContentLoaded', function() {
    var searchInput = document.getElementById('search-doctor');
    var cards = document.querySelectorAll('.doctolib-card');
    var countEl = document.getElementById('doctor-count');
    if (searchInput) {
        searchInput.addEventListener('input', function() {
            var query = this.value.toLowerCase();
            var visible = 0;
            cards.forEach(function(card) {
                var name = card.getAttribute('data-name') || '';
                var specialty = card.getAttribute('data-specialty') || '';
                if (!query || name.includes(query) || specialty.includes(query)) {
                    card.style.display = 'flex';
                    visible++;
                } else {
                    card.style.display = 'none';
                }
            });
            if (countEl) countEl.textContent = visible;
        });
    }
});

document.addEventListener('DOMContentLoaded', function() {
    if (typeof flatpickr !== 'undefined') {
        flatpickr("#appointment_date", {
            enableTime: true,
            dateFormat: "Y-m-d\\TH:i",
            altInput: true,
            altFormat: "d/m/Y à H:i",
            locale: "fr",
            minDate: "today",
            minTime: "08:00",
            maxTime: "17:00",
            time_24hr: true,
            disable: [ function(date) { return (date.getDay() === 0 || date.getDay() === 6); } ]
        });
    }
});
